41	static json safe_args_parse(const std::string & to_parse) {
42	    std::string stripped = to_parse;
43	    if (to_parse.at(0) == '"' && to_parse.at(to_parse.length() - 1) == '"') {
44	        stripped = to_parse.substr(1, to_parse.length() - 1);
45	    }
46	    try {
47	        return json::parse(stripped);
48	    } catch (json::exception & e) {
49	        return stripped;
50	    }
51	}
