72	json common_chat_msg::to_json_oaicompat(bool concat_typed_text) const {
73	    if (!content.empty() && !content_parts.empty()) {
74	        throw std::runtime_error("Cannot specify both content and content_parts");
75	    }
76	    json jmsg {
77	        {"role", role},
78	    };
79	    if (!content.empty()) {
80	        jmsg["content"] = content;
81	    } else if (!content_parts.empty()) {
82	        if (concat_typed_text) {
83	            std::string text;
84	            bool last_was_media_marker = false;
85	            // join parts with newline, do not add newline before or after media markers
86	            for (const auto & part : content_parts) {
87	                bool add_new_line = true;
88	                if (part.type == "text") {
89	                    add_new_line = !last_was_media_marker && !text.empty();
90	                    last_was_media_marker = false;
91	                } else if (part.type == "media_marker") {
92	                    add_new_line = false;
93	                    last_was_media_marker = true;
94	                } else {
95	                    LOG_WRN("Ignoring content part type: %s\n", part.type.c_str());
96	                    continue;
97	                }
98	
99	                if (add_new_line) {
100	                    text += '\n';
101	                }
102	
103	                text += part.text;
104	            }
105	            jmsg["content"] = text;
106	        } else {
107	            auto & parts = jmsg["content"] = json::array();
108	            for (const auto & part : content_parts) {
109	                parts.push_back({
110	                    {"type", part.type},
111	                    {"text", part.text},
112	                });
113	            }
114	        }
115	    } else {
116	        jmsg["content"] = "";
117	    }
118	    if (!reasoning_content.empty()) {
119	        jmsg["reasoning_content"] = reasoning_content;
120	    }
121	    if (!tool_name.empty()) {
122	        jmsg["name"] = tool_name;
123	    }
124	    if (!tool_call_id.empty()) {
125	        jmsg["tool_call_id"] = tool_call_id;
126	    }
127	    if (!tool_calls.empty()) {
128	        jmsg["tool_calls"] = json::array();
129	        auto & jtool_calls = jmsg["tool_calls"];
130	        for (const auto & tool_call : tool_calls) {
131	            json tc {
132	                {"type", "function"},
133	                {"function", {
134	                    {"name", tool_call.name},
135	                    {"arguments", json(tool_call.arguments)},
136	                }},
137	            };
138	            if (!tool_call.id.empty()) {
139	                tc["id"] = tool_call.id;
140	            }
141	            // Some templates generate and require an id (sometimes in a very specific format, e.g. Mistral Nemo).
142	            // We only generate a random id for the ones that don't generate one by themselves
143	            // (they also won't get to see it as their template likely doesn't use it, so it's all for the client)
144	            // {"id", tc.id.empty() ? gen_tool_call_id() : tc.id},
145	            jtool_calls.push_back(tc);
146	        }
147	    }
148	
149	    return jmsg;
150	}
