152	std::vector<common_chat_msg_diff> common_chat_msg_diff::compute_diffs(const common_chat_msg & msg_prv,
153	                                                                      const common_chat_msg & msg_new) {
154	    std::vector<common_chat_msg_diff> diffs;
155	    if (msg_new.tool_calls.size() > msg_prv.tool_calls.size()) {
156	        diffs.reserve(msg_new.tool_calls.size() - msg_prv.tool_calls.size() + 3);
157	    } else {
158	        diffs.reserve(3);
159	    }
160	
161	    // TODO: these can become expensive for long messages - how to optimize?
162	    if (msg_prv.reasoning_content != msg_new.reasoning_content) {
163	        auto & diff                  = diffs.emplace_back();
164	        diff.reasoning_content_delta = string_diff(msg_prv.reasoning_content, msg_new.reasoning_content);
165	    }
166	    if (msg_prv.content != msg_new.content) {
167	        auto & diff        = diffs.emplace_back();
168	        diff.content_delta = string_diff(msg_prv.content, msg_new.content);
169	    }
170	
171	    if (msg_new.tool_calls.size() < msg_prv.tool_calls.size()) {
172	        std::string err = "Invalid diff: now finding less tool calls!\n";
173	        err += "  Previous (" + std::to_string(msg_prv.tool_calls.size()) + "):\n";
174	        for (const auto & tc : msg_prv.tool_calls) {
175	            err += "    - name: '" + tc.name + "', args: '" + tc.arguments + "'\n";
176	        }
177	        err += "  Current (" + std::to_string(msg_new.tool_calls.size()) + "):\n";
178	        for (const auto & tc : msg_new.tool_calls) {
179	            err += "    - name: '" + tc.name + "', args: '" + tc.arguments + "'\n";
180	        }
181	        err += "  Current msg text content:\n" + msg_new.content + "\n";
182	        throw std::runtime_error(err);
183	    }
184	
185	    if (!msg_prv.tool_calls.empty()) {
186	        const auto   idx  = msg_prv.tool_calls.size() - 1;
187	        const auto & pref = msg_prv.tool_calls[idx];
188	        const auto & newf = msg_new.tool_calls[idx];
189	        // Allow tool name to change during incremental parsing:
190	        // - empty -> non-empty (initial discovery)
191	        // - prefix -> longer string (name grows as more input is parsed)
192	        if (pref.name != newf.name && !pref.name.empty() && !newf.name.empty()) {
193	            // Check if one is a prefix of the other (for incremental parsing where names grow or shrink)
194	            bool is_prefix = (newf.name.rfind(pref.name, 0) == 0);
195	            if (!is_prefix) {
196	                LOG_ERR("Tool call mismatch: prev='%s' new='%s'\n", pref.name.c_str(), newf.name.c_str());
197	                throw std::runtime_error("Invalid diff: tool call mismatch!");
198	            }
199	        }
200	        const auto args_diff = string_diff(pref.arguments, newf.arguments);
201	        if (!args_diff.empty() || pref.id != newf.id || pref.name != newf.name) {
202	            auto & diff          = diffs.emplace_back();
203	            diff.tool_call_index = idx;
204	            if (pref.id != newf.id || pref.name != newf.name) {
205	                diff.tool_call_delta.id   = newf.id;
206	                diff.tool_call_delta.name = newf.name;
207	            }
208	            diff.tool_call_delta.arguments = args_diff;
209	        }
210	    }
211	    for (size_t idx = msg_prv.tool_calls.size(); idx < msg_new.tool_calls.size(); ++idx) {
212	        auto & diff          = diffs.emplace_back();
213	        diff.tool_call_index = idx;
214	        diff.tool_call_delta = msg_new.tool_calls[idx];
215	    }
216	
217	    return diffs;
218	}
