230	common_chat_tool_choice common_chat_tool_choice_parse_oaicompat(const std::string & tool_choice) {
231	    if (tool_choice == "auto") {
232	        return COMMON_CHAT_TOOL_CHOICE_AUTO;
233	    }
234	    if (tool_choice == "none") {
235	        return COMMON_CHAT_TOOL_CHOICE_NONE;
236	    }
237	    if (tool_choice == "required") {
238	        return COMMON_CHAT_TOOL_CHOICE_REQUIRED;
239	    }
240	    throw std::invalid_argument("Invalid tool_choice: " + tool_choice);
241	}
