243	bool common_chat_templates_support_enable_thinking(const common_chat_templates * chat_templates) {
244	    common_chat_templates_inputs inputs;
245	    inputs.reasoning_format = COMMON_REASONING_FORMAT_DEEPSEEK;
246	    common_chat_msg msg;
247	    msg.role    = "user";
248	    msg.content = "test";
249	    inputs.messages = { msg };
250	    inputs.enable_thinking = true;
251	    inputs.add_generation_prompt = true;
252	    inputs.reasoning_format = COMMON_REASONING_FORMAT_DEEPSEEK;
253	
254	    auto params = common_chat_templates_apply(chat_templates, inputs);
255	    return params.supports_thinking;
256	}
