189	
190	    for (const auto & entry : std::filesystem::directory_iterator(dir_path)) {
191	        // only process .jinja files
192	        if (entry.path().extension() == ".jinja" && entry.is_regular_file()) {
193	            test_count++;
194	            std::cout << "\n\n=== RUNNING TEMPLATE FILE: " << entry.path().string() << " ===\n";
195	            std::ifstream infile(entry.path());
196	            std::string contents((std::istreambuf_iterator<char>(infile)), std::istreambuf_iterator<char>());
197	            try {
198	                run_single(contents, input, use_common);
199	            } catch (const std::exception & e) {
200	                std::cout << "Exception: " << e.what() << "\n";
201	                std::cout << "=== ERROR WITH TEMPLATE FILE: " << entry.path().string() << " ===\n";
202	                failed_tests.push_back(entry.path().string());
203	                if (stop_on_first_fail) {
204	                    break;
205	                }
206	            }
207	        }
208	    }
209	
210	    std::cout << "\n\n=== TEST SUMMARY ===\n";
211	    std::cout << "Total tests run: " << test_count << "\n";
212	    std::cout << "Total failed tests: " << failed_tests.size() << "\n";
213	    for (const auto & test : failed_tests) {
214	        std::cout << "FAILED TEST: " << test << "\n";
215	    }
216	}
