static common_chat_params common_chat_params_init_<NAME>(
    const common_chat_template & tmpl,
    const autoparser::generation_params & inputs) {

    common_chat_params data;

    // 1. PROMPT GENERATION
    data.prompt = common_chat_template_direct_apply_impl(tmpl, inputs);
    data.format = COMMON_CHAT_FORMAT_PEG_NATIVE;  // or other format

    // 2. THINKING/REASONING SUPPORT (optional)
    data.supports_thinking = true;
    data.thinking_start_tag = "<START_TAG>";
    data.thinking_end_tag = "</END_TAG>";

    // 3. PRESERVED TOKENS (tokens not to be split)
    data.preserved_tokens = {
        "token1",
        "token2",
        // ...
    };

    // 4. DETERMINE PARSING REQUIREMENTS
    auto has_tools = inputs.tools.is_array() && !inputs.tools.empty();
    auto extract_reasoning = inputs.reasoning_format != COMMON_REASONING_FORMAT_NONE;
    auto include_grammar = has_tools && inputs.tool_choice != COMMON_CHAT_TOOL_CHOICE_NONE;

    // 5. BUILD PEG PARSER
    auto parser = build_chat_peg_parser([&](common_chat_peg_builder & p) {
        auto generation_prompt = p.prefix(inputs.generation_prompt, START_MARKER);
        auto end = p.end();

        auto reasoning = p.eps();
        if (extract_reasoning && inputs.enable_thinking) {
            reasoning = p.optional(START_TAG + p.reasoning(p.until(END_TAG)) + END_TAG);
        }

        if (!has_tools || inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_NONE) {
            return generation_prompt + reasoning + p.content(p.rest()) + end;
        }

        // Build tool choice rules
        auto tool_choice = p.choice();
        foreach_function(inputs.tools, [&](const json & tool) {
            const auto & function = tool.at("function");
            std::string name = function.at("name");
            const auto & schema = function.at("parameters");

            // Build parser rule for this tool
            auto tool_parser = p.tool(
                p.tool_open(p.tool_name(p.literal(name)) + TOOL_SEPARATOR) +
                p.tool_args(p.schema(p.json(), "tool-" + name + "-schema", schema)) +
                p.tool_close(TOOL_CLOSE_MARKER)
            );

            tool_choice |= p.rule("tool-" + name, tool_parser);
        });

        auto min_calls = inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_REQUIRED ? 1 : 0;
        auto max_calls = inputs.parallel_tool_calls ? -1 : 1;
        auto tool_calls = p.trigger_rule("tool-call", 
            p.repeat(TOOL_START_MARKER + tool_choice, min_calls, max_calls));

        return generation_prompt + reasoning + 
               p.content(p.until(TOOL_START_MARKER)) + tool_calls + end;
    });

    data.parser = parser.save();

    // 6. GENERATE GRAMMAR (if tools present)
    if (include_grammar) {
        data.grammar_lazy = inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_AUTO;

        data.grammar = build_grammar([&](const common_grammar_builder & builder) {
            foreach_function(inputs.tools, [&](const json & tool) {
                const auto & function = tool.at("function");
                auto schema = function.at("parameters");
                builder.resolve_refs(schema);
            });
            parser.build_grammar(builder, data.grammar_lazy);
        });

        data.grammar_triggers = {
            { COMMON_GRAMMAR_TRIGGER_TYPE_WORD, TOOL_START_MARKER }
        };
    }

    return data;
}
