Here is the complete plan:

---

## Plan: Add `mistral-instruct-v3` Chat Template Handler

### What I found

After reading `common/chat.cpp`, `common/chat-peg-parser.h`, `src/llama-chat.cpp`, and `models/templates/mistralai-Mistral-Nemo-Instruct-2407.jinja` in full:

**The Mistral Instruct v0.3 format** (Nemo-Instruct-2407 and kin) is identified by these token markers in the template source:
- `[INST]` / `[/INST]` — user turns  
- `[AVAILABLE_TOOLS]` / `[/AVAILABLE_TOOLS]` — tool list  
- `[TOOL_CALLS][{…}]` — tool call responses (JSON array with `name`, `arguments`, `id` fields)  
- **No** `[SYSTEM_PROMPT]` (that belongs to Ministral 3 / v7, already handled)  
- **No** `[ARGS]` (Ministral 3's argument marker)

All seven existing specialized handlers in `common_chat_try_specialized_template` are pattern-matched on unique tokens. None of them touch `[INST]` or `[AVAILABLE_TOOLS]`, so there is zero ordering conflict.

---

### Changes — only `common/chat.cpp`

**Step 1 – New handler function** (insert after `common_chat_params_init_gigachat_v3` closes, before `namespace workaround {`)

```cpp
static common_chat_params common_chat_params_init_mistral_instruct_v3(
        const common_chat_template &          tmpl,
        const autoparser::generation_params & inputs) {

    common_chat_params data;
    data.prompt            = common_chat_template_direct_apply_impl(tmpl, inputs);
    data.format            = COMMON_CHAT_FORMAT_PEG_NATIVE;
    data.supports_thinking = false;
    data.preserved_tokens  = { "[TOOL_CALLS]" };

    auto has_tools       = inputs.tools.is_array() && !inputs.tools.empty();
    auto include_grammar = has_tools && inputs.tool_choice != COMMON_CHAT_TOOL_CHOICE_NONE;

    auto parser = build_chat_peg_parser([&](common_chat_peg_builder & p) {
        auto generation_prompt = p.prefix(inputs.generation_prompt, "[TOOL_CALLS]");

        if (!has_tools || inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_NONE) {
            include_grammar = false;
            return generation_prompt + p.content(p.rest());
        }

        // Format: [TOOL_CALLS][{"name":"…","arguments":{…},"id":"…"}, …]
        auto tools_parser = p.standard_json_tools(
            "[TOOL_CALLS]", "",
            inputs.tools, inputs.parallel_tool_calls,
            inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_REQUIRED,
            "name", "arguments",
            /*array_wrapped=*/true, /*function_is_key=*/false,
            "id", "",
            { "name", "arguments", "id" }
        );

        return generation_prompt + p.content(p.until("[TOOL_CALLS]")) + tools_parser;
    });

    data.parser = parser.save();

    if (include_grammar) {
        data.grammar_lazy = has_tools && inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_AUTO;
        data.grammar = build_grammar([&](const common_grammar_builder & builder) {
            foreach_function(inputs.tools, [&](const json & tool) {
                builder.resolve_refs(tool.at("function").at("parameters"));
            });
            parser.build_grammar(builder, data.grammar_lazy);
        });
        data.grammar_triggers = { { COMMON_GRAMMAR_TRIGGER_TYPE_WORD, "[TOOL_CALLS]" } };
    }

    return data;
}
```

**Step 2 – Detection clause** (append inside `common_chat_try_specialized_template`, after GigaChatV3 block, before `return std::nullopt`)

```cpp
    // Mistral Instruct v0.3 — [INST]/[/INST] turns + [AVAILABLE_TOOLS]
    // Distinguished from Ministral 3 / v7 by absence of [SYSTEM_PROMPT]
    if (src.find("[INST]") != std::string::npos &&
        src.find("[AVAILABLE_TOOLS]") != std::string::npos &&
        src.find("[SYSTEM_PROMPT]") == std::string::npos) {
        LOG_DBG("Using specialized template: Mistral Instruct v0.3\n");
        return common_chat_params_init_mistral_instruct_v3(tmpl, params);
    }
```

